using System.Collections.Concurrent;
using sv_451525c72b50432fbb4d29ee4f7c19ba.Models;

namespace sv_451525c72b50432fbb4d29ee4f7c19ba.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by a session cookie.
/// Accessible from both static SSR (layout) and interactive server (pages) contexts.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();
    private DateTime _lastCleanup = DateTime.UtcNow;
    private static readonly TimeSpan Expiry = TimeSpan.FromHours(4);

    public WizardState GetOrCreate(string sessionId)
    {
        CleanupIfNeeded();
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public WizardState? TryGet(string sessionId)
    {
        if (_states.TryGetValue(sessionId, out var state))
        {
            state.LastAccessed = DateTime.UtcNow;
            return state;
        }
        return null;
    }

    public void Save(string sessionId, WizardState state)
    {
        state.LastAccessed = DateTime.UtcNow;
        _states[sessionId] = state;
    }

    private void CleanupIfNeeded()
    {
        if (DateTime.UtcNow - _lastCleanup < TimeSpan.FromMinutes(30))
            return;

        _lastCleanup = DateTime.UtcNow;
        var cutoff = DateTime.UtcNow - Expiry;
        foreach (var key in _states.Keys)
        {
            if (_states.TryGetValue(key, out var s) && s.LastAccessed < cutoff)
                _states.TryRemove(key, out _);
        }
    }
}

using Microsoft.AspNetCore.Components;
using sv_451525c72b50432fbb4d29ee4f7c19ba.Models;
using sv_451525c72b50432fbb4d29ee4f7c19ba.Services;

namespace sv_451525c72b50432fbb4d29ee4f7c19ba.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles session ID bridging across
/// the static pre-render / interactive server boundary using PersistentComponentState.
/// </summary>
public abstract class WizardPageBase : ComponentBase
{
    [Inject] protected WizardStateService WizardService { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;

    protected string SessionId { get; private set; } = "";
    protected WizardState State { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            // Static pre-render phase — HttpContext is available
            SessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
        }
        else
        {
            // Interactive phase — restored from persisted state
            SessionId = restored ?? "";
        }

        if (!string.IsNullOrEmpty(SessionId))
        {
            State = WizardService.GetOrCreate(SessionId);
        }
    }

    protected void SaveAndNavigate(string url, int completedStep)
    {
        State.CompletedSteps.Add(completedStep);
        WizardService.Save(SessionId, State);
        Navigation.NavigateTo(url);
    }

    public void Dispose() => _subscription.Dispose();
}

@inherits LayoutComponentBase
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Services
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Models
@inject WizardStateService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<div class="wizard-container">
    <header class="wizard-header">
        <h2>Job Application</h2>
        <nav class="wizard-steps" aria-label="Application steps">
            @for (int i = 0; i < _steps.Length; i++)
            {
                var step = _steps[i];
                var stepNum = i + 1;
                var isCurrent = stepNum == _currentStep;
                var isCompleted = _completedSteps.Contains(stepNum);
                var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step";

                <a href="@step.Url" class="@cssClass" aria-current="@(isCurrent ? "step" : null)">
                    <span class="step-number">
                        @if (isCompleted && !isCurrent)
                        {
                            <span aria-hidden="true">✓</span>
                        }
                        else
                        {
                            @stepNum
                        }
                    </span>
                    <span class="step-label">@step.Label</span>
                </a>

                @if (stepNum < _steps.Length)
                {
                    <span class="step-connector" aria-hidden="true"></span>
                }
            }
        </nav>
        <div class="progress-text" role="status">Step @_currentStep of @_steps.Length</div>
    </header>

    <main class="wizard-content">
        @Body
    </main>
</div>

@code {
    private static readonly (string Url, string Label)[] _steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private int _currentStep = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = new Uri(Navigation.Uri).AbsolutePath.TrimEnd('/');
        _currentStep = path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1,
        };

        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            var state = WizardService.TryGet(sessionId);
            if (state is not null)
            {
                _completedSteps = state.CompletedSteps;
            }
        }
    }
}

.wizard-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 1rem;
}

.wizard-header {
    text-align: center;
    margin-bottom: 2rem;
}

.wizard-header h2 {
    margin-bottom: 1.5rem;
    color: #333;
}

.wizard-steps {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 0.75rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: #999;
    gap: 0.25rem;
    padding: 0.25rem 0.75rem;
    transition: color 0.2s;
}

.step:hover {
    color: #555;
}

.step-number {
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    background: #e0e0e0;
    color: #666;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
}

.step.current .step-number {
    background: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background: #198754;
    color: white;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-label {
    font-size: 0.8rem;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background: #e0e0e0;
    align-self: flex-start;
    margin-top: 1rem;
}

.progress-text {
    font-size: 0.875rem;
    color: #666;
}

.wizard-content {
    background: white;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 2rem;
}

