@using sv_451525c72b50432fbb4d29ee4f7c19ba.Models
@inject WizardStateService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<div class="wizard-container">
    <header class="wizard-header">
        <h2>Job Application</h2>
        <nav class="wizard-steps" aria-label="Application steps">
            @for (int i = 0; i < _steps.Length; i++)
            {
                var step = _steps[i];
                var stepNum = i + 1;
                var isCurrent = stepNum == _currentStep;
                var isCompleted = _completedSteps.Contains(stepNum);
                var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step";

                <a href="@step.Url" class="@cssClass" aria-current="@(isCurrent ? "step" : null)">
                    <span class="step-number">
                        @if (isCompleted && !isCurrent)
                        {
                            <span aria-hidden="true">✓</span>
                        }
                        else
                        {
                            @stepNum
                        }
                    </span>
                    <span class="step-label">@step.Label</span>
                </a>

                @if (stepNum < _steps.Length)
                {
                    <span class="step-connector" aria-hidden="true"></span>
                }
            }
        </nav>
        <div class="progress-text" role="status">Step @_currentStep of @_steps.Length</div>
    </header>

    <main class="wizard-content">
        @Body
    </main>
</div>

@code {
    private static readonly (string Url, string Label)[] _steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private int _currentStep = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = new Uri(Navigation.Uri).AbsolutePath.TrimEnd('/');
        _currentStep = path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1,
        };

        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            var state = WizardService.TryGet(sessionId);
            if (state is not null)
            {
                _completedSteps = state.CompletedSteps;
            }
        }
    }
}

