toolArgs.file_text:
.wizard-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 1rem;
}

.wizard-header {
    text-align: center;
    margin-bottom: 2rem;
}

.wizard-header h2 {
    margin-bottom: 1.5rem;
    color: #333;
}

.wizard-steps {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 0.75rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: #999;
    gap: 0.25rem;
    padding: 0.25rem 0.75rem;
    transition: color 0.2s;
}

.step:hover {
    color: #555;
}

.step-number {
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    background: #e0e0e0;
    color: #666;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
}

.step.current .step-number {
    background: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background: #198754;
    color: white;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-label {
    font-size: 0.8rem;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background: #e0e0e0;
    align-self: flex-start;
    margin-top: 1rem;
}

.progress-text {
    font-size: 0.875rem;
    color: #666;
}

.wizard-content {
    background: white;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 2rem;
}

