toolArgs.file_text:
@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase
@implements IDisposable
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Components.Layout

<PageTitle>Personal Info – Application</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="State.PersonalInfo" OnValidSubmit="Next" FormName="personalInfo">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText @bind-Value="State.PersonalInfo.Name" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText @bind-Value="State.PersonalInfo.Email" class="form-control" type="email" />
    </div>
    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next →</button>
    </div>
</EditForm>

@code {
    private void Next()
    {
        SaveAndNavigate("/apply/experience", completedStep: 1);
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase
@implements IDisposable
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Models
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Components.Layout

<PageTitle>Experience – Application</PageTitle>

<h3>Work Experience</h3>

@if (State.Experience.Count == 0)
{
    <p class="text-muted">No entries yet. Add your work history below.</p>
}

@for (int i = 0; i < State.Experience.Count; i++)
{
    var index = i;
    var entry = State.Experience[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-start">
                <h6 class="card-title mb-3">Position @(index + 1)</h6>
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
            </div>
            <div class="row">
                <div class="col-md-4 mb-2">
                    <label class="form-label">Job Title</label>
                    <input class="form-control" @bind="entry.Title" />
                </div>
                <div class="col-md-4 mb-2">
                    <label class="form-label">Company</label>
                    <input class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-4 mb-2">
                    <label class="form-label">Years</label>
                    <input type="number" class="form-control" @bind="entry.Years" min="0" />
                </div>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Position</button>

<div class="d-flex justify-content-between">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddEntry()
    {
        State.Experience.Add(new JobHistory());
    }

    private void RemoveEntry(int index)
    {
        State.Experience.RemoveAt(index);
    }

    private void Next()
    {
        SaveAndNavigate("/apply/references", completedStep: 2);
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase
@implements IDisposable
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Models
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Components.Layout

<PageTitle>References – Application</PageTitle>

<h3>References</h3>

@if (State.References.Count == 0)
{
    <p class="text-muted">No references yet. Add your reference contacts below.</p>
}

@for (int i = 0; i < State.References.Count; i++)
{
    var index = i;
    var entry = State.References[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-start">
                <h6 class="card-title mb-3">Reference @(index + 1)</h6>
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
            </div>
            <div class="row">
                <div class="col-md-4 mb-2">
                    <label class="form-label">Name</label>
                    <input class="form-control" @bind="entry.Name" />
                </div>
                <div class="col-md-4 mb-2">
                    <label class="form-label">Email</label>
                    <input class="form-control" type="email" @bind="entry.Email" />
                </div>
                <div class="col-md-4 mb-2">
                    <label class="form-label">Relationship</label>
                    <input class="form-control" @bind="entry.Relationship" />
                </div>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <a href="/apply/experience" class="btn btn-outline-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddEntry()
    {
        State.References.Add(new ReferenceContact());
    }

    private void RemoveEntry(int index)
    {
        State.References.RemoveAt(index);
    }

    private void Next()
    {
        SaveAndNavigate("/apply/review", completedStep: 3);
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase
@implements IDisposable
@using sv_451525c72b50432fbb4d29ee4f7c19ba.Components.Layout

<PageTitle>Review – Application</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@(string.IsNullOrWhiteSpace(State.PersonalInfo.Name) ? "—" : State.PersonalInfo.Name)</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@(string.IsNullOrWhiteSpace(State.PersonalInfo.Email) ? "—" : State.PersonalInfo.Email)</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (State.Experience.Count == 0)
        {
            <p class="text-muted mb-0">No experience entries provided.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var job in State.Experience)
                {
                    <li class="list-group-item">
                        <strong>@job.Title</strong> at @job.Company — @job.Years year(s)
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (State.References.Count == 0)
        {
            <p class="text-muted mb-0">No references provided.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var r in State.References)
                {
                    <li class="list-group-item">
                        <strong>@r.Name</strong> (@r.Relationship) — @r.Email
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/references" class="btn btn-outline-secondary">← Back</a>
    <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3" role="alert">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        State.CompletedSteps.Add(4);
        WizardService.Save(SessionId, State);
        _submitted = true;
    }
}

